// Build batch Kite quote request for prediction symbols
const predictions = $input.all().map(i => i.json);
const uniqueSymbols = [...new Set(predictions.map(p => `NSE:${p.symbol}`))];
const queryParams = uniqueSymbols.map(s => `i=${s}`).join('&');

return [{
  json: {
    predictions: predictions,
    quote_url: `https://api.kite.trade/quote?${queryParams}`
  }
}];

// Check each prediction against current prices
const quotes = $input.first().json.data || {};
const predictions = $('Build Quote URL').item.json.predictions;
const updates = [];

for (const pred of predictions) {
  const key = `NSE:${pred.symbol}`;
  const quote = quotes[key];
  if (!quote) continue;

  const currentPrice = quote.last_price;
  const targetPrice = parseFloat(pred.target_price);
  const predictionPrice = parseFloat(pred.current_price_at_prediction);
  const createdAt = new Date(pred.created_at);
  const now = new Date();

  // Calculate trading sessions elapsed (approximate: weekdays)
  const msElapsed = now - createdAt;
  const daysElapsed = msElapsed / (1000 * 60 * 60 * 24);
  const sessionsElapsed = Math.floor(daysElapsed * 5 / 7); // Rough weekday count

  let status = 'pending';
  let hit = false;
  let accuracyScore = null;

  // Check if target hit
  if (pred.direction === 'UP' && currentPrice >= targetPrice) {
    status = 'hit';
    hit = true;
    // Accuracy: how close was our timeline prediction?
    const predictedAvg = (pred.predicted_timeframe_min + pred.predicted_timeframe_max) / 2;
    const timelineError = Math.abs(sessionsElapsed - predictedAvg);
    accuracyScore = Math.max(0, 100 - timelineError * 10);
  } else if (pred.direction === 'DOWN' && currentPrice <= targetPrice) {
    status = 'hit';
    hit = true;
    const predictedAvg = (pred.predicted_timeframe_min + pred.predicted_timeframe_max) / 2;
    const timelineError = Math.abs(sessionsElapsed - predictedAvg);
    accuracyScore = Math.max(0, 100 - timelineError * 10);
  }

  // Check if expired (past max timeframe)
  if (!hit && sessionsElapsed > pred.predicted_timeframe_max) {
    // Check if direction was at least correct
    const directionCorrect = 
      (pred.direction === 'UP' && currentPrice > predictionPrice) ||
      (pred.direction === 'DOWN' && currentPrice < predictionPrice);

    status = 'expired';
    accuracyScore = directionCorrect ? 30 : 0; // Partial credit for direction
  }

  if (status !== 'pending') {
    updates.push({
      prediction_id: pred.id,
      user_id: pred.user_id,
      symbol: pred.symbol,
      status: status,
      actual_hit: hit,
      actual_sessions_taken: sessionsElapsed,
      accuracy_score: accuracyScore,
      current_price: currentPrice,
      target_price: targetPrice,
      direction: pred.direction,
      chat_id: pred.alerts_chat_id || pred.private_chat_id
    });
  }
}

return updates.map(u => ({ json: u }));

// Format notification for resolved prediction
const p = $('Evaluate Predictions').item.json;
const emoji = p.actual_hit ? '✅' : '❌';
const hitText = p.actual_hit ? 'TARGET HIT!' : 'Prediction expired';

const msg = `${emoji} *Prediction Update: ${p.symbol}*\n\n` +
  `Direction: ${p.direction} | Target: ₹${p.target_price}\n` +
  `Current: ₹${p.current_price}\n` +
  `Sessions taken: ${p.actual_sessions_taken}\n` +
  `Result: *${hitText}*\n` +
  `Accuracy score: ${p.accuracy_score}/100`;

return [{ json: { chat_id: p.chat_id, message: msg } }];
